import{_ as t,o as e,c as o,O as i}from"./chunks/framework.bdcb0ee1.js";const m=JSON.parse('{"title":"Topics & Posts","description":"","frontmatter":{},"headers":[],"relativePath":"userguide/posting.md","filePath":"userguide/posting.md","lastUpdated":1773167653000}'),a={name:"userguide/posting.md"},n=i('<h1 id="topics-posts" tabindex="-1">Topics &amp; Posts <a class="header-anchor" href="#topics-posts" aria-label="Permalink to &quot;Topics &amp; Posts&quot;">​</a></h1><nav class="table-of-contents"><ul><li><a href="#creating-a-topic">Creating a topic</a></li><li><a href="#replying-to-a-topic">Replying to a topic</a></li><li><a href="#quoting-and-multi-quote">Quoting and multi-quote</a><ul><li><a href="#quoting-a-single-post">Quoting a single post</a></li><li><a href="#multi-quote">Multi-quote</a></li></ul></li><li><a href="#mentioning-users">Mentioning users</a></li><li><a href="#editing-your-posts">Editing your posts</a></li><li><a href="#editing-your-topic-title-description">Editing your topic title &amp; description</a></li><li><a href="#reactions">Reactions</a></li></ul></nav><h2 id="creating-a-topic" tabindex="-1">Creating a topic <a class="header-anchor" href="#creating-a-topic" aria-label="Permalink to &quot;Creating a topic&quot;">​</a></h2><p>To start a new topic, navigate to the forum you want to post in and click <strong>Create Topic</strong>. You will be presented with the following fields:</p><ul><li><strong>Title</strong> — the topic heading (up to 255 characters). Must contain at least one letter or number.</li><li><strong>Description</strong> — an optional short summary (up to 100 characters) displayed below the title in topic listings.</li><li><strong>Content</strong> — the body of your post, written in BBCode. Must be between 5 and 65,000 characters.</li><li><strong>Label</strong> — if the forum has topic labels configured, you can choose one to categorise your topic.</li><li><strong>Poll</strong> — optionally attach a poll to your topic (see <a href="/userguide/polls.html">Polls</a> for details).</li></ul><img width="1942" height="1351" alt="image" src="https://github.com/user-attachments/assets/bed147f3-6508-468f-8d2b-19a35321e003"><p>After posting, you will automatically watch the topic and receive notifications when others reply.</p><h2 id="replying-to-a-topic" tabindex="-1">Replying to a topic <a class="header-anchor" href="#replying-to-a-topic" aria-label="Permalink to &quot;Replying to a topic&quot;">​</a></h2><p>Scroll to the bottom of any topic to find the reply box. Type your response using BBCode formatting and click <strong>Post Reply</strong>. Replies must be between 5 and 5,000 characters.</p><p>When you reply to a topic, you will automatically watch it (unless you have disabled this in your notification preferences).</p><img width="1940" height="580" alt="image" src="https://github.com/user-attachments/assets/d237040e-bca7-443d-a1a9-e0e720b7ce65"><h2 id="quoting-and-multi-quote" tabindex="-1">Quoting and multi-quote <a class="header-anchor" href="#quoting-and-multi-quote" aria-label="Permalink to &quot;Quoting and multi-quote&quot;">​</a></h2><h3 id="quoting-a-single-post" tabindex="-1">Quoting a single post <a class="header-anchor" href="#quoting-a-single-post" aria-label="Permalink to &quot;Quoting a single post&quot;">​</a></h3><p>Click the <strong>Quote</strong> button on any post to insert it into your reply. The quoted text will be wrapped in <code>[quote=Username]...[/quote]</code> tags.</p><h3 id="multi-quote" tabindex="-1">Multi-quote <a class="header-anchor" href="#multi-quote" aria-label="Permalink to &quot;Multi-quote&quot;">​</a></h3><p>To quote multiple posts in a single reply:</p><ol><li>Tick the checkbox on each post you want to quote.</li><li>Click <strong>Insert Quotes</strong> when you are ready to compose your reply.</li><li>All selected quotes will be inserted into the reply box.</li></ol><img width="1947" height="1598" alt="image" src="https://github.com/user-attachments/assets/cb73d55f-0ae9-4502-aebb-600cd0de03d8"><h2 id="mentioning-users" tabindex="-1">Mentioning users <a class="header-anchor" href="#mentioning-users" aria-label="Permalink to &quot;Mentioning users&quot;">​</a></h2><p>Type <code>@username</code> in your post to mention another member. They will receive a notification that they were mentioned. Usernames are matched automatically — just type the <code>@</code> symbol followed by the username.</p><h2 id="editing-your-posts" tabindex="-1">Editing your posts <a class="header-anchor" href="#editing-your-posts" aria-label="Permalink to &quot;Editing your posts&quot;">​</a></h2><p>Click the <strong>Edit</strong> button on your own post to update its content. Edited posts display a note showing when the post was last edited.</p><h2 id="editing-your-topic-title-description" tabindex="-1">Editing your topic title &amp; description <a class="header-anchor" href="#editing-your-topic-title-description" aria-label="Permalink to &quot;Editing your topic title &amp; description&quot;">​</a></h2><p>If you make a mistake with your topic title, description or want to change the label you can do this by navigating to the &quot;Edit Topic Title&quot; link next to the opening post you created.</p><img width="1934" height="146" alt="image" src="https://github.com/user-attachments/assets/0eeac6b1-a371-45e1-bee4-934cf004da33"><p>From here you will be presented with fields to update the title, description and change label if applicable. Only the topic author, moderators and admins can edit the topic.</p><img width="1946" height="450" alt="image" src="https://github.com/user-attachments/assets/d2bce745-18f3-4b4e-804e-a9e5cd080cd9"><h2 id="reactions" tabindex="-1">Reactions <a class="header-anchor" href="#reactions" aria-label="Permalink to &quot;Reactions&quot;">​</a></h2><p>Click on a reaction emoji below any post to react to it. Click the same emoji again to remove your reaction. You can see who has reacted to a post by hovering over or clicking the reaction count.</p><p>Reactions contribute to the post author&#39;s reputation and may count towards achievements.</p><img width="1931" height="314" alt="image" src="https://github.com/user-attachments/assets/d746223e-9351-45ab-99c7-d39297d595e0">',31),s=[n];function r(l,c,u,h,p,d){return e(),o("div",null,s)}const y=t(a,[["render",r]]);export{m as __pageData,y as default};
